{
  "type": "DRAG_FILL",
  "lessonText": "Engage in a gamified challenge to reinforce your understanding of game development concepts.",
  "data": {
    "challenges": [
      {
        "instruction": "Fill in the blanks to complete the game loop structure.",
        "codeTemplate": "while ___: \n    ___() \n    ___()",
        "options": ["running", "update", "render"],
        "correctAnswer": "running,update,render",
        "explanation": "The game loop continues running, updating game state, and rendering graphics."
      },
      {
        "instruction": "Identify the key components of a game engine.",
        "codeTemplate": "class ___: \n    def ___(): \n        ___()",
        "options": ["GameEngine", "initialize", "loadAssets"],
        "correctAnswer": "GameEngine,initialize,loadAssets",
        "explanation": "A game engine class initializes and loads necessary assets for the game."
      },
      {
        "instruction": "Complete the function to handle player input.",
        "codeTemplate": "def ___(event): \n    if ___ == 'KEYDOWN': \n        ___()",
        "options": ["handleInput", "event.type", "processInput"],
        "correctAnswer": "handleInput,event.type,processInput",
        "explanation": "The function processes player input based on the event type."
      },
      {
        "instruction": "Fill in the blanks to describe the rendering process.",
        "codeTemplate": "def ___(): \n    ___() \n    ___()",
        "options": ["renderScene", "clearScreen", "drawObjects"],
        "correctAnswer": "renderScene,clearScreen,drawObjects",
        "explanation": "Rendering involves clearing the screen and drawing game objects."
      }
    ]
  }
}
